  1→/*
  2→ * ESP32 Single Rotary Encoder Reader
  3→ * ====================================
  4→ * 대상 엔코더: Autonics E40H8-1024-3-T-24
  5→ *   - PPR  : 1024 pulses/rev
  6→ *   - 출력  : Totem-pole, 12~24VDC
  7→ *   - 배선  : BLACK=A, WHITE=B, ORANGE=Z, BROWN=+V, BLUE=0V, SHIELD=FG
  8→ *
  9→ * 해상도 : 1024 PPR × 4배체배 = 4096 counts/rev
 10→ *
 11→ * v2.0 변경사항:
 12→ *   - 소프트웨어 ISR → ESP32 하드웨어 PCNT 방식으로 전환
 13→ *   - 인터럽트 누락 없이 CPU 개입 없는 정확한 카운트
 14→ *   - Z 채널 인터럽트 완전 제거 (노이즈 원인)
 15→ *
 16→ * 통신 포트 (동시 동작):
 17→ *   - Serial  : USB CDC
 18→ *   - Serial1 : GPIO16(TX) / GPIO17(RX) 하드웨어 UART
 19→ *
 20→ * 명령어:
 21→ *   ZERO    - 현재 위치를 0으로 리셋
 22→ *   SETHOME - 현재 위치를 절대 원점으로 NVS 저장
 23→ *   STATUS  - 현재 상태 즉시 출력
 24→ *   INFO    - 시스템 정보 출력
 25→ *
 26→ * 작성일: 2026-02-25
 27→ */
 28→
 29→#include <Arduino.h>
 30→#include <Preferences.h>
 31→#include "driver/pulse_cnt.h"
 32→
 33→// ============================================================
 34→// 핀 설정
 35→// ============================================================
 36→#define ENC_PIN_A   34    // OUT A (BLACK)
 37→#define ENC_PIN_B   35    // OUT B (WHITE)
 38→// Z 채널 미사용 (PCNT 방식에서 불필요)
 39→
 40→#define UART_TX_PIN 16
 41→#define UART_RX_PIN 17
 42→
 43→// ============================================================
 44→// 엔코더 설정
 45→// ============================================================
 46→#define ENCODER_PPR     1024
 47→#define COUNTS_PER_REV  (ENCODER_PPR * 4)   // 4096 CPR
 48→
 49→// PCNT 하드웨어 카운터 범위 (16비트)
 50→#define PCNT_HIGH_LIM    32767
 51→#define PCNT_LOW_LIM    -32768
 52→
 53→// ============================================================
 54→// 통신 설정
 55→// ============================================================
 56→#define SERIAL_BAUD         921600
 57→#define UPDATE_INTERVAL_MS  10      // 100Hz
 58→
 59→// ============================================================
 60→// 두 포트 동시 출력 헬퍼
 61→// ============================================================
 62→template<typename T>
 63→void comPrint(T v)          { Serial.print(v);     Serial1.print(v);     }
 64→template<typename T, typename F>
 65→void comPrint(T v, F f)     { Serial.print(v,f);   Serial1.print(v,f);   }
 66→template<typename T>
 67→void comPrintln(T v)        { Serial.println(v);   Serial1.println(v);   }
 68→template<typename T, typename F>
 69→void comPrintln(T v, F f)   { Serial.println(v,f); Serial1.println(v,f); }
 70→void comPrintln()           { Serial.println();    Serial1.println();    }
 71→
 72→// ============================================================
 73→// PCNT 전역
 74→// ============================================================
 75→static pcnt_unit_handle_t pcnt_unit_h = NULL;
 76→static volatile int32_t enc_accum = 0;  // 오버플로우 누적값
 77→
 78→// ============================================================
 79→// 글로벌 변수
 80→// ============================================================
 81→int32_t enc_offset = 0;
 82→
 83→unsigned long last_update_time = 0;
 84→unsigned long start_time       = 0;
 85→
 86→String buf_usb  = "";
 87→String buf_uart = "";
 88→
 89→Preferences preferences;
 90→
 91→// ============================================================
 92→// PCNT 오버플로우/언더플로우 콜백 (IRAM)
 93→// watch_point_val: HIGH_LIM(+32767) 또는 LOW_LIM(-32768)
 94→// ============================================================
 95→static bool IRAM_ATTR pcnt_on_reach(pcnt_unit_handle_t unit,
 96→                                     const pcnt_watch_event_data_t *edata,
 97→                                     void *user_ctx) {
 98→    int32_t *accum = (int32_t *)user_ctx;
 99→    // 오버플로우 시 65536 단위로 누적 (HIGH→+65536, LOW→-65536)
100→    if (edata->watch_point_value > 0)
101→        *accum += (int32_t)(PCNT_HIGH_LIM - PCNT_LOW_LIM + 1);
102→    else
103→        *accum -= (int32_t)(PCNT_HIGH_LIM - PCNT_LOW_LIM + 1);
104→    return false;
105→}
106→
107→// ============================================================
108→// PCNT 초기화 (4배체배 쿼드러처)
109→// ============================================================
110→void initPCNT() {
111→    // 핀 명시적 INPUT 설정 (GPIO34/35 input-only 핀)
112→    pinMode(ENC_PIN_A, INPUT);
113→    pinMode(ENC_PIN_B, INPUT);
114→
115→    // 유닛 생성
116→    pcnt_unit_config_t unit_cfg = {};
