/*
 * ESP32 Single Rotary Encoder Reader
 * ====================================
 * 대상 엔코더: Autonics E40H8-1024-3-T-24
 *   - PPR  : 1024 pulses/rev
 *   - 출력  : Totem-pole, 12~24VDC
 *   - 배선  : BLACK=A, WHITE=B, ORANGE=Z, BROWN=+V, BLUE=0V, SHIELD=FG
 *
 * 해상도 : 1024 PPR × 4배체배 = 4096 counts/rev
 *
 * v2.0 변경사항:
 *   - 소프트웨어 ISR → ESP32 하드웨어 PCNT 방식으로 전환
 *   - 인터럽트 누락 없이 CPU 개입 없는 정확한 카운트
 *   - Z 채널 인터럽트 완전 제거 (노이즈 원인)
 *
 * 통신 포트 (동시 동작):
 *   - Serial  : USB CDC
 *   - Serial1 : GPIO16(TX) / GPIO17(RX) 하드웨어 UART
 *
 * 명령어:
 *   ZERO    - 현재 위치를 0으로 리셋
 *   SETHOME - 현재 위치를 절대 원점으로 NVS 저장
 *   STATUS  - 현재 상태 즉시 출력
 *   INFO    - 시스템 정보 출력
 *
 * 작성일: 2026-02-25
 */

#include <Arduino.h>
#include <Preferences.h>
#include "driver/pulse_cnt.h"

// ============================================================
// 핀 설정
// ============================================================
#define ENC_PIN_A   34    // OUT A (BLACK)
#define ENC_PIN_B   35    // OUT B (WHITE)
// Z 채널 미사용 (PCNT 방식에서 불필요)

#define UART_TX_PIN 16
#define UART_RX_PIN 17

// ============================================================
// 엔코더 설정
// ============================================================
#define ENCODER_PPR     1024
#define COUNTS_PER_REV  (ENCODER_PPR * 4)   // 4096 CPR

// PCNT 하드웨어 카운터 범위 (16비트)
#define PCNT_HIGH_LIM    32767
#define PCNT_LOW_LIM    -32768

// ============================================================
// 통신 설정
// ============================================================
#define SERIAL_BAUD         921600
#define UPDATE_INTERVAL_MS  10      // 100Hz

// ============================================================
// 두 포트 동시 출력 헬퍼
// ============================================================
template<typename T>
void comPrint(T v)          { Serial.print(v);     Serial1.print(v);     }
template<typename T, typename F>
void comPrint(T v, F f)     { Serial.print(v,f);   Serial1.print(v,f);   }
template<typename T>
void comPrintln(T v)        { Serial.println(v);   Serial1.println(v);   }
template<typename T, typename F>
void comPrintln(T v, F f)   { Serial.println(v,f); Serial1.println(v,f); }
void comPrintln()           { Serial.println();    Serial1.println();    }

// ============================================================
// PCNT 전역
// ============================================================
static pcnt_unit_handle_t pcnt_unit_h = NULL;
static volatile int32_t enc_accum = 0;  // 오버플로우 누적값

// ============================================================
// 글로벌 변수
// ============================================================
int32_t enc_offset = 0;

unsigned long last_update_time = 0;
unsigned long start_time       = 0;

String buf_usb  = "";
String buf_uart = "";

Preferences preferences;

// ============================================================
// PCNT 오버플로우/언더플로우 콜백 (IRAM)
// watch_point_val: HIGH_LIM(+32767) 또는 LOW_LIM(-32768)
// ============================================================
static bool IRAM_ATTR pcnt_on_reach(pcnt_unit_handle_t unit,
                                     const pcnt_watch_event_data_t *edata,
                                     void *user_ctx) {
    int32_t *accum = (int32_t *)user_ctx;
    // 오버플로우 시 65536 단위로 누적 (HIGH→+65536, LOW→-65536)
    if (edata->watch_point_value > 0)
        *accum += (int32_t)(PCNT_HIGH_LIM - PCNT_LOW_LIM + 1);
    else
        *accum -= (int32_t)(PCNT_HIGH_LIM - PCNT_LOW_LIM + 1);
    return false;
}

// ============================================================
// PCNT 초기화 (4배체배 쿼드러처)
// ============================================================
void initPCNT() {
    // 핀 명시적 INPUT 설정 (GPIO34/35 input-only 핀)
    pinMode(ENC_PIN_A, INPUT);
    pinMode(ENC_PIN_B, INPUT);

    // 유닛 생성
    pcnt_unit_config_t unit_cfg = {};
    unit_cfg.low_limit  = PCNT_LOW_LIM;
    unit_cfg.high_limit = PCNT_HIGH_LIM;
    pcnt_new_unit(&unit_cfg, &pcnt_unit_h);

    // 글리치 필터 비활성화 (레벨 컨버터 신호 지연으로 인한 엣지 누락 방지)

    // 채널 A: edge=A핀, level=B핀 (B 레벨에 따라 방향 결정)
    pcnt_channel_handle_t chan_a;
    pcnt_chan_config_t chan_a_cfg = {};
    chan_a_cfg.edge_gpio_num  = ENC_PIN_A;
    chan_a_cfg.level_gpio_num = ENC_PIN_B;
    pcnt_new_channel(pcnt_unit_h, &chan_a_cfg, &chan_a);
    pcnt_channel_set_edge_action(chan_a,
        PCNT_CHANNEL_EDGE_ACTION_INCREASE,   // A 상승엣지 → CW=+
        PCNT_CHANNEL_EDGE_ACTION_DECREASE);  // A 하강엣지
    pcnt_channel_set_level_action(chan_a,
        PCNT_CHANNEL_LEVEL_ACTION_KEEP,      // B=High: 방향 유지
        PCNT_CHANNEL_LEVEL_ACTION_INVERSE);  // B=Low:  방향 반전

    // 채널 B: edge=B핀, level=A핀 (A 레벨에 따라 방향 결정)
    pcnt_channel_handle_t chan_b;
    pcnt_chan_config_t chan_b_cfg = {};
    chan_b_cfg.edge_gpio_num  = ENC_PIN_B;
    chan_b_cfg.level_gpio_num = ENC_PIN_A;
    pcnt_new_channel(pcnt_unit_h, &chan_b_cfg, &chan_b);
    pcnt_channel_set_edge_action(chan_b,
        PCNT_CHANNEL_EDGE_ACTION_DECREASE,   // B 상승엣지 → CW=+
        PCNT_CHANNEL_EDGE_ACTION_INCREASE);  // B 하강엣지
    pcnt_channel_set_level_action(chan_b,
        PCNT_CHANNEL_LEVEL_ACTION_KEEP,      // A=High: 방향 유지
        PCNT_CHANNEL_LEVEL_ACTION_INVERSE);  // A=Low:  방향 반전

    // 오버플로우/언더플로우 워치포인트 등록
    pcnt_unit_add_watch_point(pcnt_unit_h, PCNT_HIGH_LIM);
    pcnt_unit_add_watch_point(pcnt_unit_h, PCNT_LOW_LIM);

    pcnt_event_callbacks_t cbs = {};
    cbs.on_reach = pcnt_on_reach;
    pcnt_unit_register_event_callbacks(pcnt_unit_h, &cbs, (void*)&enc_accum);

    pcnt_unit_enable(pcnt_unit_h);
    pcnt_unit_clear_count(pcnt_unit_h);
    pcnt_unit_start(pcnt_unit_h);
}

// ============================================================
// 현재 카운트 읽기 (오버플로우 누적 포함)
// ============================================================
int32_t getPCNTCount() {
    int raw = 0;
    pcnt_unit_get_count(pcnt_unit_h, &raw);
    return enc_accum + (int32_t)raw;
}

// ============================================================
// 절대 카운트 (오프셋 적용)
// ============================================================
inline int32_t getAbsCount() {
    return getPCNTCount() - enc_offset;
}

// ============================================================
// NVS 저장/로드
// ============================================================
void saveOffset() {
    preferences.begin("enc", false);
    preferences.putInt("offset", enc_offset);
    preferences.end();
}

void loadOffset() {
    preferences.begin("enc", true);
    enc_offset = preferences.getInt("offset", 0);
    preferences.end();
}

// ============================================================
// JSON 전송
// ============================================================
void sendEncoderData() {
    int32_t abs_cnt = getAbsCount();
    float   deg     = (float)abs_cnt / COUNTS_PER_REV * 360.0f;
    unsigned long ts = millis() - start_time;

    comPrint("{\"t\":");
    comPrint(ts);
    comPrint(",\"cnt\":");
    comPrint(abs_cnt);
    comPrint(",\"deg\":");
    comPrint(deg, 2);
    comPrintln(",\"ok\":true}");
}

// ============================================================
// 명령 처리
// ============================================================
void processCommand(String cmd) {
    cmd.trim();
    cmd.toUpperCase();

    // ZERO: 현재 위치를 0으로 리셋
    if (cmd == "ZERO") {
        enc_offset = getPCNTCount();
        comPrintln("{\"cmd\":\"ZERO\",\"ok\":true}");
    }

    // SETHOME: 현재 위치를 절대 원점으로 NVS 저장
    else if (cmd == "SETHOME") {
        enc_offset = getPCNTCount();
        saveOffset();
        comPrint("{\"cmd\":\"SETHOME\",\"offset\":");
        comPrint(enc_offset);
        comPrintln(",\"ok\":true}");
    }

    // STATUS
    else if (cmd == "STATUS" || cmd == "?") {
        sendEncoderData();
    }

    // INFO
    else if (cmd == "INFO") {
        comPrint("{\"model\":\"E40H8-1024-3-T-24\"");
        comPrint(",\"mode\":\"PCNT_HW\"");
        comPrint(",\"ppr\":");    comPrint(ENCODER_PPR);
        comPrint(",\"cpr\":");    comPrint(COUNTS_PER_REV);
        comPrint(",\"hz\":");     comPrint(1000 / UPDATE_INTERVAL_MS);
        comPrint(",\"baud\":");   comPrint(SERIAL_BAUD);
        comPrint(",\"offset\":"); comPrint(enc_offset);
        comPrintln(",\"ok\":true}");
    }

    // 알 수 없는 명령
    else {
        comPrint("{\"cmd\":\"UNKNOWN\",\"input\":\"");
        comPrint(cmd);
        comPrintln("\",\"ok\":false}");
    }
}

// ============================================================
// 수신 버퍼 처리
// ============================================================
void processBuf(char c, String& buf) {
    if (c == '\n' || c == '\r') {
        if (buf.length() > 0) {
            processCommand(buf);
            buf = "";
        }
    } else {
        buf += c;
        if (buf.length() > 64) buf = "";
    }
}

// ============================================================
// setup
// ============================================================
void setup() {
    Serial.begin(SERIAL_BAUD);
    while (!Serial) { delay(10); }

    Serial1.begin(SERIAL_BAUD, SERIAL_8N1, UART_RX_PIN, UART_TX_PIN);

    // NVS에서 오프셋 복원
    loadOffset();

    // PCNT 하드웨어 초기화
    initPCNT();

    start_time       = millis();
    last_update_time = start_time;

    comPrint("{\"msg\":\"E40H8 PCNT Ready\"");
    comPrint(",\"cpr\":"); comPrint(COUNTS_PER_REV);
    comPrint(",\"offset\":"); comPrint(enc_offset);
    comPrintln(",\"ok\":true}");
}

// ============================================================
// loop
// ============================================================
void loop() {
    unsigned long now = millis();

    // 주기적 데이터 전송 (100Hz)
    if (now - last_update_time >= UPDATE_INTERVAL_MS) {
        last_update_time = now;
        sendEncoderData();
    }

    // USB CDC 수신
    while (Serial.available() > 0) {
        processBuf((char)Serial.read(), buf_usb);
    }

    // GPIO UART 수신
    while (Serial1.available() > 0) {
        processBuf((char)Serial1.read(), buf_uart);
    }
}

