void setupEncoder1Interrupts() {
  attachInterrupt(digitalPinToInterrupt(ENC1_PIN_A), enc1_isr, CHANGE);
  attachInterrupt(digitalPinToInterrupt(ENC1_PIN_B), enc1_isr, CHANGE);
}

void setupEncoder2Interrupts() {
  attachInterrupt(digitalPinToInterrupt(ENC2_PIN_A), enc2_isr, CHANGE);
  attachInterrupt(digitalPinToInterrupt(ENC2_PIN_B), enc2_isr, CHANGE);
}

void setupEncoder3Interrupts() {
  attachInterrupt(digitalPinToInterrupt(ENC3_PIN_A), enc3_isr, CHANGE);
  attachInterrupt(digitalPinToInterrupt(ENC3_PIN_B), enc3_isr, CHANGE);
}

// ============================================================
// 초기화
// ============================================================
void setup() {
  // 시리얼 초기화
  Serial.begin(SERIAL_BAUD);
  while (!Serial) { delay(10); }

  // 핀 설정 - Encoder 1
  pinMode(ENC1_PIN_A, INPUT);
  pinMode(ENC1_PIN_B, INPUT);
  pinMode(ENC1_PIN_Z, INPUT);

  // 핀 설정 - Encoder 2
  pinMode(ENC2_PIN_A, INPUT);
  pinMode(ENC2_PIN_B, INPUT);
  pinMode(ENC2_PIN_Z, INPUT);

  // 핀 설정 - Encoder 3
  pinMode(ENC3_PIN_A, INPUT);
  pinMode(ENC3_PIN_B, INPUT);
  pinMode(ENC3_PIN_Z, INPUT);

  // NVS에서 저장된 값 불러오기
  loadOffsets();
  loadPositions();
  loadEnabledState();

  // 초기 상태 읽기
  enc1_last_state = (digitalRead(ENC1_PIN_B) << 1) | digitalRead(ENC1_PIN_A);
  enc2_last_state = (digitalRead(ENC2_PIN_B) << 1) | digitalRead(ENC2_PIN_A);
  enc3_last_state = (digitalRead(ENC3_PIN_B) << 1) | digitalRead(ENC3_PIN_A);

  // 인터럽트 설정 (모든 엔코더에 대해 설정, 활성화 여부와 무관하게)
  // 비활성화된 엔코더도 인터럽트는 유지하고, 출력만 제어
  setupEncoder1Interrupts();
  setupEncoder2Interrupts();
  setupEncoder3Interrupts();

  // 시작 시간 기록
  start_time = millis();
  last_update_time = start_time;

  // 시작 메시지
  comPrint("{\"msg\":\"ESP32 Triple Encoder Ready\"");
  comPrint(",\"active_encoders\":");
  comPrint(getActiveEncoderCount());
  if (enc1_enabled) { Serial.print(",\"e1_offset\":"); Serial.print(enc1_offset); }
  if (enc2_enabled) { Serial.print(",\"e2_offset\":"); Serial.print(enc2_offset); }
  if (enc3_enabled) { Serial.print(",\"e3_offset\":"); Serial.print(enc3_offset); }
  comPrint(",\"e1_en\":");
  comPrint(enc1_enabled ? "true" : "false");
  comPrint(",\"e2_en\":");
  comPrint(enc2_enabled ? "true" : "false");
  comPrint(",\"e3_en\":");
  comPrint(enc3_enabled ? "true" : "false");
  comPrintln(",\"ok\":true}");

  delay(100);
}

// ============================================================
// 메인 루프
// ============================================================
void loop() {
  unsigned long current_time = millis();

  // 주기적 데이터 전송
  if (current_time - last_update_time >= UPDATE_INTERVAL_MS) {
    last_update_time = current_time;
    sendEncoderData();
  }

  // USB CDC 수신
  while (Serial.available() > 0) {
    processBuf((char)Serial.read(), buf_usb);
  }

  // GPIO UART 수신
  while (Serial1.available() > 0) {
    processBuf((char)Serial1.read(), buf_uart);
  }
}

