}

// ============================================================
// NVS에서 오프셋 불러오기
// ============================================================
void loadOffsets() {
  preferences.begin("encoder", true);
  enc1_offset = preferences.getInt("e1_offset", 0);
  enc2_offset = preferences.getInt("e2_offset", 0);
  enc3_offset = preferences.getInt("e3_offset", 0);
