// ============================================================
// 위치 저장
// ============================================================
void savePosition(int pos) {
  if (pos < 1 || pos > MAX_POSITIONS) return;

  int idx = pos - 1;
  saved_positions[idx][0] = getAbsoluteCount1();
  saved_positions[idx][1] = getAbsoluteCount2();
  saved_positions[idx][2] = getAbsoluteCount3();

  preferences.begin("encoder", false);
  String key1 = "pos" + String(pos) + "_e1";
  String key2 = "pos" + String(pos) + "_e2";
  String key3 = "pos" + String(pos) + "_e3";
  preferences.putInt(key1.c_str(), saved_positions[idx][0]);
  preferences.putInt(key2.c_str(), saved_positions[idx][1]);
  preferences.putInt(key3.c_str(), saved_positions[idx][2]);
  preferences.end();

  comPrint("{\"cmd\":\"SAVE\",\"pos\":");
  comPrint(pos);
  if (enc1_enabled) {
    comPrint(",\"e1\":");
    comPrint(saved_positions[idx][0]);
  }
  if (enc2_enabled) {
    comPrint(",\"e2\":");
    comPrint(saved_positions[idx][1]);
  }
  if (enc3_enabled) {
    comPrint(",\"e3\":");
    comPrint(saved_positions[idx][2]);
  }
  comPrintln(",\"ok\":true}");
}

// ============================================================
// 저장된 위치 불러오기
// ============================================================
void loadPositions() {
  preferences.begin("encoder", true);
  for (int i = 0; i < MAX_POSITIONS; i++) {
    String key1 = "pos" + String(i+1) + "_e1";
    String key2 = "pos" + String(i+1) + "_e2";
    String key3 = "pos" + String(i+1) + "_e3";
    saved_positions[i][0] = preferences.getInt(key1.c_str(), 0);
    saved_positions[i][1] = preferences.getInt(key2.c_str(), 0);
    saved_positions[i][2] = preferences.getInt(key3.c_str(), 0);
  }
  preferences.end();
}

// ============================================================
// 저장된 위치 정보 전송
// ============================================================
void sendPositionInfo(int pos) {
  if (pos < 1 || pos > MAX_POSITIONS) return;

  int idx = pos - 1;

  comPrint("{\"cmd\":\"POS\",\"pos\":");
  comPrint(pos);

  if (enc1_enabled) {
    float deg1 = countToDegree(saved_positions[idx][0]);
    comPrint(",\"e1\":{\"cnt\":");
    comPrint(saved_positions[idx][0]);
    comPrint(",\"deg\":");
    comPrint(deg1, 1);
    comPrint("}");
  }

  if (enc2_enabled) {
    float deg2 = countToDegree(saved_positions[idx][1]);
    comPrint(",\"e2\":{\"cnt\":");
    comPrint(saved_positions[idx][1]);
    comPrint(",\"deg\":");
    comPrint(deg2, 1);
    comPrint("}");
  }

  if (enc3_enabled) {
    float deg3 = countToDegree(saved_positions[idx][2]);
    comPrint(",\"e3\":{\"cnt\":");
    comPrint(saved_positions[idx][2]);
    comPrint(",\"deg\":");
    comPrint(deg3, 1);
    comPrint("}");
  }

  comPrintln(",\"ok\":true}");
}

// ============================================================
// 모든 저장된 위치 정보 전송
// ============================================================
void sendAllPositions() {
  comPrint("{\"cmd\":\"POSITIONS\",\"data\":[");
  for (int i = 0; i < MAX_POSITIONS; i++) {
    if (i > 0) comPrint(",");
    comPrint("{\"pos\":");
    comPrint(i + 1);
    if (enc1_enabled) {
      comPrint(",\"e1\":");
      comPrint(saved_positions[i][0]);
    }
    if (enc2_enabled) {
      comPrint(",\"e2\":");
      comPrint(saved_positions[i][1]);
    }
    if (enc3_enabled) {
      comPrint(",\"e3\":");
      comPrint(saved_positions[i][2]);
    }
    comPrint("}");
  }
  comPrintln("],\"ok\":true}");
}

// ============================================================
// 활성화된 엔코더 수 반환
// ============================================================
int getActiveEncoderCount() {
  int count = 0;
  if (enc1_enabled) count++;
  if (enc2_enabled) count++;
  if (enc3_enabled) count++;
  return count;
}

// ============================================================
// 수신 버퍼 처리
// ============================================================
void processBuf(char c, String& buf) {
  if (c == '\n' || c == '\r') {
    if (buf.length() > 0) {
      processCommand(buf);
      buf = "";
    }
  } else {
    buf += c;
    if (buf.length() > 64) buf = "";
  }
}

// ============================================================
// 시리얼 명령 처리
// ============================================================
void processCommand(String cmd) {
  cmd.trim();
  cmd.toUpperCase();

  // ZERO 명령들
  if (cmd == "ZERO 1" || cmd == "ZERO1") {
    enc1_count = 0;
    comPrintln("{\"cmd\":\"ZERO\",\"enc\":1,\"ok\":true}");
  }
  else if (cmd == "ZERO 2" || cmd == "ZERO2") {
    enc2_count = 0;
    comPrintln("{\"cmd\":\"ZERO\",\"enc\":2,\"ok\":true}");
  }
  else if (cmd == "ZERO 3" || cmd == "ZERO3") {
    enc3_count = 0;
    comPrintln("{\"cmd\":\"ZERO\",\"enc\":3,\"ok\":true}");
  }
  else if (cmd == "ZERO ALL" || cmd == "ZEROALL" || cmd == "ZERO") {
    enc1_count = 0;
    enc2_count = 0;
    enc3_count = 0;
    comPrintln("{\"cmd\":\"ZERO\",\"enc\":\"all\",\"ok\":true}");
  }

  // ★ 엔코더 활성화/비활성화
  else if (cmd.startsWith("ENABLE ")) {
    int enc = cmd.substring(7).toInt();
    if (enc == 1) { enc1_enabled = true; saveEnabledState(); comPrintln("{\"cmd\":\"ENABLE\",\"enc\":1,\"ok\":true}"); }
    else if (enc == 2) { enc2_enabled = true; saveEnabledState(); comPrintln("{\"cmd\":\"ENABLE\",\"enc\":2,\"ok\":true}"); }
    else if (enc == 3) { enc3_enabled = true; saveEnabledState(); comPrintln("{\"cmd\":\"ENABLE\",\"enc\":3,\"ok\":true}"); }
    else { comPrintln("{\"cmd\":\"ENABLE\",\"ok\":false,\"error\":\"Invalid encoder (1-3)\"}"); }
  }
  else if (cmd.startsWith("DISABLE ")) {
    int enc = cmd.substring(8).toInt();
    if (enc == 1) { enc1_enabled = false; saveEnabledState(); comPrintln("{\"cmd\":\"DISABLE\",\"enc\":1,\"ok\":true}"); }
    else if (enc == 2) { enc2_enabled = false; saveEnabledState(); comPrintln("{\"cmd\":\"DISABLE\",\"enc\":2,\"ok\":true}"); }
    else if (enc == 3) { enc3_enabled = false; saveEnabledState(); comPrintln("{\"cmd\":\"DISABLE\",\"enc\":3,\"ok\":true}"); }
    else { comPrintln("{\"cmd\":\"DISABLE\",\"ok\":false,\"error\":\"Invalid encoder (1-3)\"}"); }
  }

  // ★ 절대값 원점 설정 (현재 위치를 0으로, NVS에 저장)
  else if (cmd == "SETHOME" || cmd == "SET HOME" || cmd == "ABSOLUTE") {
    enc1_offset = enc1_count;
    enc2_offset = enc2_count;
    enc3_offset = enc3_count;
    saveOffsets();
    comPrint("{\"cmd\":\"SETHOME\"");
    if (enc1_enabled) { comPrint(",\"e1_offset\":"); comPrint(enc1_offset); }
    if (enc2_enabled) { comPrint(",\"e2_offset\":"); comPrint(enc2_offset); }
    if (enc3_enabled) { comPrint(",\"e3_offset\":"); comPrint(enc3_offset); }
    comPrintln(",\"ok\":true}");
  }

  // ★ 개별 엔코더 원점 설정
  else if (cmd == "SETHOME 1" || cmd == "SETHOME1") {
    enc1_offset = enc1_count;
    saveOffsets();
    comPrint("{\"cmd\":\"SETHOME\",\"enc\":1,\"offset\":");
    comPrint(enc1_offset);
    comPrintln(",\"ok\":true}");
  }
  else if (cmd == "SETHOME 2" || cmd == "SETHOME2") {
    enc2_offset = enc2_count;
    saveOffsets();
    comPrint("{\"cmd\":\"SETHOME\",\"enc\":2,\"offset\":");
    comPrint(enc2_offset);
    comPrintln(",\"ok\":true}");
  }
  else if (cmd == "SETHOME 3" || cmd == "SETHOME3") {
    enc3_offset = enc3_count;
    saveOffsets();
    comPrint("{\"cmd\":\"SETHOME\",\"enc\":3,\"offset\":");
    comPrint(enc3_offset);
    comPrintln(",\"ok\":true}");
  }

  // ★ 위치 저장 (SAVE 1 ~ SAVE 100)
  else if (cmd.startsWith("SAVE ")) {
    int pos = cmd.substring(5).toInt();
    savePosition(pos);
  }
  else if (cmd.startsWith("SAVE")) {
    int pos = cmd.substring(4).toInt();
    if (pos > 0) savePosition(pos);
  }

  // ★ 지정된 값으로 위치 저장 (SAVEAT pos e1 e2 e3) - 재정렬용
  else if (cmd.startsWith("SAVEAT ")) {
    // "SAVEAT 1 100 200 300" 형태
    String params = cmd.substring(7);
    int space1 = params.indexOf(' ');
    int space2 = params.indexOf(' ', space1 + 1);
    int space3 = params.indexOf(' ', space2 + 1);

    if (space1 > 0 && space2 > space1) {
      int pos = params.substring(0, space1).toInt();
      int32_t e1 = params.substring(space1 + 1, space2).toInt();
      int32_t e2 = 0;
      int32_t e3 = 0;

      if (space3 > space2) {
        e2 = params.substring(space2 + 1, space3).toInt();
        e3 = params.substring(space3 + 1).toInt();
      } else {
        e2 = params.substring(space2 + 1).toInt();
      }

      if (pos >= 1 && pos <= MAX_POSITIONS) {
        int idx = pos - 1;
        saved_positions[idx][0] = e1;
        saved_positions[idx][1] = e2;
        saved_positions[idx][2] = e3;

        preferences.begin("encoder", false);
        String key1 = "pos" + String(pos) + "_e1";
        String key2 = "pos" + String(pos) + "_e2";
        String key3 = "pos" + String(pos) + "_e3";
        preferences.putInt(key1.c_str(), e1);
        preferences.putInt(key2.c_str(), e2);
        preferences.putInt(key3.c_str(), e3);
        preferences.end();

        comPrint("{\"cmd\":\"SAVEAT\",\"pos\":");
        comPrint(pos);
        comPrint(",\"e1\":");
        comPrint(e1);
        comPrint(",\"e2\":");
        comPrint(e2);
        comPrint(",\"e3\":");
        comPrint(e3);
        comPrintln(",\"ok\":true}");
      }
    }
  }

  // ★ 저장된 위치 조회
  else if (cmd.startsWith("GET ")) {
    int pos = cmd.substring(4).toInt();
    sendPositionInfo(pos);
  }
  else if (cmd == "GETALL" || cmd == "GET ALL" || cmd == "POSITIONS") {
    sendAllPositions();
  }

  // ★ 위치 삭제 (DELETE 1 ~ DELETE 100)
  else if (cmd.startsWith("DELETE ")) {
    int pos = cmd.substring(7).toInt();
    if (pos >= 1 && pos <= MAX_POSITIONS) {
      int idx = pos - 1;
      saved_positions[idx][0] = 0;
      saved_positions[idx][1] = 0;
      saved_positions[idx][2] = 0;

      preferences.begin("encoder", false);
      String key1 = "pos" + String(pos) + "_e1";
      String key2 = "pos" + String(pos) + "_e2";
      String key3 = "pos" + String(pos) + "_e3";
      preferences.putInt(key1.c_str(), 0);
      preferences.putInt(key2.c_str(), 0);
      preferences.putInt(key3.c_str(), 0);
      preferences.end();

      comPrint("{\"cmd\":\"DELETE\",\"pos\":");
      comPrint(pos);
      comPrintln(",\"ok\":true}");
    } else {
      comPrintln("{\"cmd\":\"DELETE\",\"ok\":false,\"error\":\"Invalid position\"}");
    }
  }

  // ★ 모든 위치 삭제 (CLEAR)
  else if (cmd == "CLEAR" || cmd == "CLEARALL") {
    preferences.begin("encoder", false);
    for (int i = 0; i < MAX_POSITIONS; i++) {
      saved_positions[i][0] = 0;
      saved_positions[i][1] = 0;
      saved_positions[i][2] = 0;
      String key1 = "pos" + String(i+1) + "_e1";
      String key2 = "pos" + String(i+1) + "_e2";
      String key3 = "pos" + String(i+1) + "_e3";
      preferences.putInt(key1.c_str(), 0);
      preferences.putInt(key2.c_str(), 0);
      preferences.putInt(key3.c_str(), 0);
    }
    preferences.end();
    comPrintln("{\"cmd\":\"CLEAR\",\"ok\":true}");
  }

  // 상태 조회
  else if (cmd == "STATUS" || cmd == "?") {
    sendEncoderData();
  }

  // 시스템 정보
  else if (cmd == "INFO") {
    comPrint("{\"ppr\":");
    comPrint(ENCODER_PPR);
    comPrint(",\"cpr\":");
    comPrint(COUNTS_PER_REV);
    comPrint(",\"hz\":");
    comPrint(1000 / UPDATE_INTERVAL_MS);
    comPrint(",\"baud\":");
    comPrint(SERIAL_BAUD);
    comPrint(",\"positions\":");
    comPrint(MAX_POSITIONS);
    comPrint(",\"max_encoders\":");
    comPrint(MAX_ENCODERS);
    comPrint(",\"active_encoders\":");
    comPrint(getActiveEncoderCount());
    comPrint(",\"e1_en\":");
    comPrint(enc1_enabled ? "true" : "false");
    comPrint(",\"e2_en\":");
    comPrint(enc2_enabled ? "true" : "false");
    comPrint(",\"e3_en\":");
    comPrint(enc3_enabled ? "true" : "false");
    comPrintln(",\"ok\":true}");
  }

  // ★ 공차 설정 (TOLERANCE 5 또는 TOL 5)
  else if (cmd.startsWith("TOLERANCE ") || cmd.startsWith("TOL ")) {
    int tol = cmd.substring(cmd.indexOf(' ') + 1).toInt();
    if (tol >= 1 && tol <= 100) {
      position_tolerance = tol;
      float tol_deg = (float)tol / COUNTS_PER_REV * 360.0;
      comPrint("{\"cmd\":\"TOLERANCE\",\"cnt\":");
      comPrint(tol);
      comPrint(",\"deg\":");
      comPrint(tol_deg, 1);
      comPrintln(",\"ok\":true}");
    } else {
      comPrintln("{\"cmd\":\"TOLERANCE\",\"ok\":false,\"error\":\"Invalid (1-100)\"}");
    }
  }

  // 알 수 없는 명령
  else {
    comPrint("{\"cmd\":\"UNKNOWN\",\"input\":\"");
    comPrint(cmd);
    comPrintln("\",\"ok\":false}");
  }
}

// ============================================================
// 엔코더 데이터 전송 (JSON 포맷)
// ============================================================
void sendEncoderData() {
  noInterrupts();
  int32_t cnt1 = enc1_count;
  int32_t cnt2 = enc2_count;
  int32_t cnt3 = enc3_count;
  interrupts();

  // 절대 카운트 (오프셋 적용)
  int32_t abs1 = cnt1 - enc1_offset;
  int32_t abs2 = cnt2 - enc2_offset;
  int32_t abs3 = cnt3 - enc3_offset;

  // 타임스탬프 (ms)
  unsigned long timestamp = millis() - start_time;

  // JSON 출력
  comPrint("{\"t\":");
  comPrint(timestamp);

  if (enc1_enabled) {
    float deg1 = countToDegree(abs1);
    comPrint(",\"e1\":{\"cnt\":");
    comPrint(abs1);
    comPrint(",\"deg\":");
    comPrint(deg1, 1);
    comPrint("}");
  }

  if (enc2_enabled) {
    float deg2 = countToDegree(abs2);
    comPrint(",\"e2\":{\"cnt\":");
    comPrint(abs2);
    comPrint(",\"deg\":");
    comPrint(deg2, 1);
    comPrint("}");
  }

  if (enc3_enabled) {
    float deg3 = countToDegree(abs3);
    comPrint(",\"e3\":{\"cnt\":");
    comPrint(abs3);
    comPrint(",\"deg\":");
    comPrint(deg3, 1);
    comPrint("}");
  }

  comPrintln(",\"ok\":true}");
}

// ============================================================
// 인터럽트 설정/해제 함수
// ============================================================
void setupEncoder1Interrupts() {
  attachInterrupt(digitalPinToInterrupt(ENC1_PIN_A), enc1_isr, CHANGE);
  attachInterrupt(digitalPinToInterrupt(ENC1_PIN_B), enc1_isr, CHANGE);
}

void setupEncoder2Interrupts() {
  attachInterrupt(digitalPinToInterrupt(ENC2_PIN_A), enc2_isr, CHANGE);
  attachInterrupt(digitalPinToInterrupt(ENC2_PIN_B), enc2_isr, CHANGE);
}

void setupEncoder3Interrupts() {
  attachInterrupt(digitalPinToInterrupt(ENC3_PIN_A), enc3_isr, CHANGE);
  attachInterrupt(digitalPinToInterrupt(ENC3_PIN_B), enc3_isr, CHANGE);
}

// ============================================================
// 초기화
// ============================================================
void setup() {
  // 시리얼 초기화
  Serial.begin(SERIAL_BAUD);
  while (!Serial) { delay(10); }

  Serial1.begin(SERIAL_BAUD, SERIAL_8N1, UART_RX_PIN, UART_TX_PIN);

  // 핀 설정 - Encoder 1
  pinMode(ENC1_PIN_A, INPUT);
  pinMode(ENC1_PIN_B, INPUT);
  pinMode(ENC1_PIN_Z, INPUT);

  // 핀 설정 - Encoder 2
  pinMode(ENC2_PIN_A, INPUT);
  pinMode(ENC2_PIN_B, INPUT);
  pinMode(ENC2_PIN_Z, INPUT);

  // 핀 설정 - Encoder 3
  pinMode(ENC3_PIN_A, INPUT);
  pinMode(ENC3_PIN_B, INPUT);
  pinMode(ENC3_PIN_Z, INPUT);

  // NVS에서 저장된 값 불러오기
  loadOffsets();
  loadPositions();
  loadEnabledState();

  // 초기 상태 읽기
  enc1_last_state = (digitalRead(ENC1_PIN_B) << 1) | digitalRead(ENC1_PIN_A);
  enc2_last_state = (digitalRead(ENC2_PIN_B) << 1) | digitalRead(ENC2_PIN_A);
  enc3_last_state = (digitalRead(ENC3_PIN_B) << 1) | digitalRead(ENC3_PIN_A);

  // 인터럽트 설정 (모든 엔코더에 대해 설정, 활성화 여부와 무관하게)
  // 비활성화된 엔코더도 인터럽트는 유지하고, 출력만 제어
  setupEncoder1Interrupts();
  setupEncoder2Interrupts();
  setupEncoder3Interrupts();

  // 시작 시간 기록
  start_time = millis();
  last_update_time = start_time;

  // 시작 메시지
  comPrint("{\"msg\":\"ESP32 Triple Encoder Ready\"");
  comPrint(",\"active_encoders\":");
  comPrint(getActiveEncoderCount());
  if (enc1_enabled) { Serial.print(",\"e1_offset\":"); Serial.print(enc1_offset); }
  if (enc2_enabled) { Serial.print(",\"e2_offset\":"); Serial.print(enc2_offset); }
  if (enc3_enabled) { Serial.print(",\"e3_offset\":"); Serial.print(enc3_offset); }
  comPrint(",\"e1_en\":");
  comPrint(enc1_enabled ? "true" : "false");
  comPrint(",\"e2_en\":");
  comPrint(enc2_enabled ? "true" : "false");
  comPrint(",\"e3_en\":");
  comPrint(enc3_enabled ? "true" : "false");
  comPrintln(",\"ok\":true}");

  delay(100);
}

// ============================================================
// 메인 루프
// ============================================================
void loop() {
  unsigned long current_time = millis();

  // 주기적 데이터 전송
  if (current_time - last_update_time >= UPDATE_INTERVAL_MS) {
    last_update_time = current_time;
    sendEncoderData();
  }

  // USB CDC 수신
  while (Serial.available() > 0) {
    processBuf((char)Serial.read(), buf_usb);
  }

  // GPIO UART 수신
  while (Serial1.available() > 0) {
    processBuf((char)Serial1.read(), buf_uart);
  }
}
